import pytest

from app.calculator import add


@pytest.mark.parametrize(
    "left,right,expected",
    [
        (2, 3, 5),
        (-4, -6, -10),
        (-1, 1, 0),
    ],
)
def test_add_parametrized(left, right, expected):
    assert add(left, right) == expected
